@use '@carbon/grid' as *;

.component {
  display: block;

  /* applies styles inside mixin on md breakpoint or below, like max-width */
  @include breakpoint-down('md') {
    display: none;
  }
}

.component {
  display: none;

  /* applies styles inside mixin on lg breakpoint and above */
  @include breakpoint('lg') {
    display: block;
  }
}

